1897 static InstructionCost getCostForIntrinsics(Intrinsic::ID ID,
1898                                             ArrayRef<const VPValue *> Operands,
1899                                             const VPRecipeWithIRFlags &R,
1900                                             ElementCount VF,
1901                                             VPCostContext &Ctx) {
1902   // Some backends analyze intrinsic arguments to determine cost. Use the
1903   // underlying value for the operand if it has one. Otherwise try to use the
1904   // operand of the underlying call instruction, if there is one. Otherwise
1905   // clear Arguments.
1906   // TODO: Rework TTI interface to be independent of concrete IR values.
1907   SmallVector<const Value *> Arguments;
