1896 /// Compute the cost for the intrinsic \p ID with \p Operands, produced by \p R.
1897 static InstructionCost getCostForIntrinsics(Intrinsic::ID ID,
1898                                             ArrayRef<const VPValue *> Operands,
1899                                             const VPRecipeWithIRFlags &R,
1900                                             ElementCount VF,
1901                                             VPCostContext &Ctx) {
1902   // Some backends analyze intrinsic arguments to determine cost. Use the
1903   // underlying value for the operand if it has one. Otherwise try to use the
1904   // operand of the underlying call instruction, if there is one. Otherwise
1905   // clear Arguments.
1906   // TODO: Rework TTI interface to be independent of concrete IR values.
1907   SmallVector<const Value *> Arguments;
1908   for (const auto &[Idx, Op] : enumerate(Operands)) {
1909     auto *V = Op->getUnderlyingValue();
1910     if (!V) {
1911       if (auto *UI = dyn_cast_or_null<CallBase>(R.getUnderlyingValue())) {
1912         Arguments.push_back(UI->getArgOperand(Idx));
1913         continue;
1914       }
1915       Arguments.clear();
1916       break;
1917     }
1918     Arguments.push_back(V);
1919   }
1920 
1921   Type *ScalarRetTy = Ctx.Types.inferScalarType(&R);
1922   Type *RetTy = VF.isVector() ? toVectorizedTy(ScalarRetTy, VF) : ScalarRetTy;
1923   SmallVector<Type *> ParamTys;
1924   for (const VPValue *Op : Operands) {
1925     ParamTys.push_back(VF.isVector()
1926                            ? toVectorTy(Ctx.Types.inferScalarType(Op), VF)
1927                            : Ctx.Types.inferScalarType(Op));
1928   }
1929 
1930   // TODO: Rework TTI interface to avoid reliance on underlying IntrinsicInst.
1931   FastMathFlags FMF =
1932       R.hasFastMathFlags() ? R.getFastMathFlags() : FastMathFlags();
1933   IntrinsicCostAttributes CostAttrs(
1934       ID, RetTy, Arguments, ParamTys, FMF,
1935       dyn_cast_or_null<IntrinsicInst>(R.getUnderlyingValue()),
1936       InstructionCost::getInvalid(), &Ctx.TLI);
1937   return Ctx.TTI.getIntrinsicInstrCost(CostAttrs, Ctx.CostKind);
1938 }
