1981 void VPHistogramRecipe::execute(VPTransformState &State) {
1982   IRBuilderBase &Builder = State.Builder;
1983 
1984   Value *Address = State.get(getOperand(0));
1985   Value *IncAmt = State.get(getOperand(1), /*IsScalar=*/true);
1986   VectorType *VTy = cast<VectorType>(Address->getType());
1987 
1988   // The histogram intrinsic requires a mask even if the recipe doesn't;
1989   // if the mask operand was omitted then all lanes should be executed and
1990   // we just need to synthesize an all-true mask.
1991   Value *Mask = nullptr;
1992   if (VPValue *VPMask = getMask())
1993     Mask = State.get(VPMask);
1994   else
1995     Mask =
1996         Builder.CreateVectorSplat(VTy->getElementCount(), Builder.getInt1(1));
1997 
1998   // If this is a subtract, we want to invert the increment amount. We may
1999   // add a separate intrinsic in future, but for now we'll try this.
2000   if (Opcode == Instruction::Sub)
2001     IncAmt = Builder.CreateNeg(IncAmt);
2002   else
2003     assert(Opcode == Instruction::Add && "only add or sub supported for now");
2004 
2005   State.Builder.CreateIntrinsic(Intrinsic::experimental_vector_histogram_add,
2006                                 {VTy, IncAmt->getType()},
2007                                 {Address, IncAmt, Mask});
2008 }
