2010 InstructionCost VPHistogramRecipe::computeCost(ElementCount VF,
2011                                                VPCostContext &Ctx) const {
2012   // FIXME: Take the gather and scatter into account as well. For now we're
2013   //        generating the same cost as the fallback path, but we'll likely
2014   //        need to create a new TTI method for determining the cost, including
2015   //        whether we can use base + vec-of-smaller-indices or just
2016   //        vec-of-pointers.
2017   assert(VF.isVector() && "Invalid VF for histogram cost");
2018   Type *AddressTy = Ctx.Types.inferScalarType(getOperand(0));
2019   VPValue *IncAmt = getOperand(1);
2020   Type *IncTy = Ctx.Types.inferScalarType(IncAmt);
2021   VectorType *VTy = VectorType::get(IncTy, VF);
2022 
2023   // Assume that a non-constant update value (or a constant != 1) requires
2024   // a multiply, and add that into the cost.
2025   InstructionCost MulCost =
2026       Ctx.TTI.getArithmeticInstrCost(Instruction::Mul, VTy, Ctx.CostKind);
2027   if (auto *CI = dyn_cast<VPConstantInt>(IncAmt))
2028     if (CI->isOne())
2029       MulCost = TTI::TCC_Free;
2030 
2031   // Find the cost of the histogram operation itself.
2032   Type *PtrTy = VectorType::get(AddressTy, VF);
2033   Type *MaskTy = VectorType::get(Type::getInt1Ty(Ctx.LLVMCtx), VF);
2034   IntrinsicCostAttributes ICA(Intrinsic::experimental_vector_histogram_add,
2035                               Type::getVoidTy(Ctx.LLVMCtx),
2036                               {PtrTy, IncTy, MaskTy});
2037 
2038   // Add the costs together with the add/sub operation.
2039   return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind) + MulCost +
2040          Ctx.TTI.getArithmeticInstrCost(Opcode, VTy, Ctx.CostKind);
2041 }
