7991 VPReplicateRecipe *VPRecipeBuilder::handleReplication(VPInstruction *VPI,
7992                                                       VFRange &Range) {
7993   auto *I = VPI->getUnderlyingInstr();
7994   bool IsUniform = LoopVectorizationPlanner::getDecisionAndClampRange(
7995       [&](ElementCount VF) { return CM.isUniformAfterVectorization(I, VF); },
7996       Range);
