8104 void LoopVectorizationPlanner::buildVPlansWithVPRecipes(ElementCount MinVF,
8105                                                         ElementCount MaxVF) {
8106   if (ElementCount::isKnownGT(MinVF, MaxVF))
8107     return;
8108 
8109   assert(OrigLoop->isInnermost() && "Inner loop expected.");
8110 
8111   const LoopAccessInfo *LAI = Legal->getLAI();
8112   LoopVersioning LVer(*LAI, LAI->getRuntimePointerChecking()->getChecks(),
8113                       OrigLoop, LI, DT, PSE.getSE());
8114   if (!LAI->getRuntimePointerChecking()->getChecks().empty() &&
8115       !LAI->getRuntimePointerChecking()->getDiffChecks()) {
8116     // Only use noalias metadata when using memory checks guaranteeing no
8117     // overlap across all iterations.
8118     LVer.prepareNoAliasMetadata();
8119   }
8120 
8121   // Create initial base VPlan0, to serve as common starting point for all
8122   // candidates built later for specific VF ranges.
8123   auto VPlan0 = VPlanTransforms::buildVPlan0(
8124       OrigLoop, *LI, Legal->getWidestInductionType(),
8125       getDebugLocFromInstOrOperands(Legal->getPrimaryInduction()), PSE, &LVer);
8126 
8127   // Create recipes for header phis.
8128   VPlanTransforms::createHeaderPhiRecipes(
8129       *VPlan0, PSE, *OrigLoop, Legal->getInductionVars(),
8130       Legal->getReductionVars(), Legal->getFixedOrderRecurrences(),
8131       CM.getInLoopReductions(), Hints.allowReordering());
8132 
8133   auto MaxVFTimes2 = MaxVF * 2;
8134   for (ElementCount VF = MinVF; ElementCount::isKnownLT(VF, MaxVFTimes2);) {
8135     VFRange SubRange = {VF, MaxVFTimes2};
8136     if (auto Plan = tryToBuildVPlanWithVPRecipes(
8137             std::unique_ptr<VPlan>(VPlan0->duplicate()), SubRange, &LVer)) {
8138       // Now optimize the initial VPlan.
8139       VPlanTransforms::hoistPredicatedLoads(*Plan, PSE, OrigLoop);
8140       VPlanTransforms::sinkPredicatedStores(*Plan, PSE, OrigLoop);
8141       RUN_VPLAN_PASS(VPlanTransforms::truncateToMinimalBitwidths, *Plan,
8142                      CM.getMinimalBitwidths());
8143       RUN_VPLAN_PASS(VPlanTransforms::optimize, *Plan);
8144       // TODO: try to put addExplicitVectorLength close to addActiveLaneMask
8145       if (CM.foldTailWithEVL()) {
8146         RUN_VPLAN_PASS(VPlanTransforms::addExplicitVectorLength, *Plan,
8147                        CM.getMaxSafeElements());
8148         RUN_VPLAN_PASS(VPlanTransforms::optimizeEVLMasks, *Plan);
8149       }
8150       assert(verifyVPlanIsValid(*Plan) && "VPlan is invalid");
8151       VPlans.push_back(std::move(Plan));
8152     }
8153     VF = SubRange.End;
8154   }
