3298 /// Returns a SCEV expression for \p Ptr if it is a pointer computation for
3299 /// which the legacy cost model computes a SCEV expression when computing the
3300 /// address cost. Computing SCEVs for VPValues is incomplete and returns
3301 /// SCEVCouldNotCompute in cases the legacy cost model can compute SCEVs. In
3302 /// those cases we fall back to the legacy cost model. Otherwise return nullptr.
3303 static const SCEV *getAddressAccessSCEV(const VPValue *Ptr,
3304                                         PredicatedScalarEvolution &PSE,
3305                                         const Loop *L) {
3306   const SCEV *Addr = vputils::getSCEVExprForVPValue(Ptr, PSE, L);
3307   if (isa<SCEVCouldNotCompute>(Addr))
3308     return Addr;
3309 
3310   return vputils::isAddressSCEVForCost(Addr, *PSE.getSE(), L) ? Addr : nullptr;
