3313 /// Returns true if \p V is used as part of the address of another load or
3314 /// store.
3315 static bool isUsedByLoadStoreAddress(const VPUser *V) {
3316   SmallPtrSet<const VPUser *, 4> Seen;
3317   SmallVector<const VPUser *> WorkList = {V};
3318 
3319   while (!WorkList.empty()) {
3320     auto *Cur = dyn_cast<VPSingleDefRecipe>(WorkList.pop_back_val());
3321     if (!Cur || !Seen.insert(Cur).second)
3322       continue;
3323 
3324     auto *Blend = dyn_cast<VPBlendRecipe>(Cur);
3325     // Skip blends that use V only through a compare by checking if any incoming
3326     // value was already visited.
3327     if (Blend && none_of(seq<unsigned>(0, Blend->getNumIncomingValues()),
3328                          [&](unsigned I) {
3329                            return Seen.contains(
3330                                Blend->getIncomingValue(I)->getDefiningRecipe());
3331                          }))
3332       continue;
3333 
3334     for (VPUser *U : Cur->users()) {
3335       if (auto *InterleaveR = dyn_cast<VPInterleaveBase>(U))
3336         if (InterleaveR->getAddr() == Cur)
3337           return true;
3338       if (auto *RepR = dyn_cast<VPReplicateRecipe>(U)) {
3339         if (RepR->getOpcode() == Instruction::Load &&
3340             RepR->getOperand(0) == Cur)
3341           return true;
3342         if (RepR->getOpcode() == Instruction::Store &&
3343             RepR->getOperand(1) == Cur)
3344           return true;
3345       }
3346       if (auto *MemR = dyn_cast<VPWidenMemoryRecipe>(U)) {
3347         if (MemR->getAddr() == Cur && MemR->isConsecutive())
3348           return true;
3349       }
3350     }
3351 
3352     // The legacy cost model only supports scalarization loads/stores with phi
3353     // addresses, if the phi is directly used as load/store address. Don't
3354     // traverse further for Blends.
3355     if (Blend)
3356       continue;
3357 
3358     append_range(WorkList, Cur->users());
3359   }
3360   return false;
3361 }
